import { SocialIcon } from "react-social-icons"
import "./sidebar.css"

function Sidebar() {
    return (
        <div class="leftside">
            <ul>
                <li><SocialIcon url="https://www.linkedin.com/in/austin-meyer-6a7609164/" /></li>
                <li><SocialIcon url="https://twitter.com/OGlobalATM" /></li>
                <li><SocialIcon url="https://github.com/ameyer12" /></li>
                <li><SocialIcon url="https://www.facebook.com/austin.meyer.58" /></li>
                <li><SocialIcon url="https://www.instagram.com/_austin.meyer_/" /></li>
            </ul>
        </div>
    )
  }

export default Sidebar;
